import{_ as d,o as e,c as o,a5 as r}from"./chunks/framework.UejvgJX4.js";const y=JSON.parse('{"title":"边界与路线图（Python）","description":"","frontmatter":{"outline":2},"headers":[],"relativePath":"sdk-py/limits.md","filePath":"sdk-py/limits.md","lastUpdated":1784005699000}'),a={name:"sdk-py/limits.md"};function s(c,t,n,i,h,l){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="边界与路线图-python" tabindex="-1">边界与路线图（Python） <a class="header-anchor" href="#边界与路线图-python" aria-label="Permalink to &quot;边界与路线图（Python）&quot;">​</a></h1><blockquote><p><strong>读完本页你能</strong>：看懂 Python 版 brainary-agent-sdk 的实现状态、它与 Rust 版的 parity 关系，以及接口全表面 × Brainary 决策的覆盖矩阵。</p></blockquote><div class="warning custom-block"><p class="custom-block-title">规划状态</p><p>Python 版 brainary-agent-sdk <strong>本身尚未实现</strong>（Rust 版在独立分支，Python 端口待排期）。本章记录的是<strong>规划中的 Python 接口面</strong>——镜像 Rust 版、命名沿用 Brainary 名，写法遵循 Python 惯用法。下表的「决策」列是<strong>接口层面</strong>的裁剪（与 Rust 版一致），「Python 实现」整体归路线图。</p></div><h2 id="rust-↔-python-parity" tabindex="-1">Rust ↔ Python parity <a class="header-anchor" href="#rust-↔-python-parity" aria-label="Permalink to &quot;Rust ↔ Python parity&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>说明</th></tr></thead><tbody><tr><td><strong>接口清单</strong></td><td>单一真源，Rust / Python 共享（见方案第 4 节）。两语言同增同减</td></tr><tr><td><strong>命名</strong></td><td>沿用 Brainary 名（<code>query</code> / <code>BrainaryClient</code> / <code>Options</code>），跨语言一致</td></tr><tr><td><strong>形态差异</strong></td><td>仅签名风格：Rust 的 <code>Result</code>/借用 ↔ Python 的异常/<code>async with</code>；Rust 的枚举 <code>match</code> ↔ Python 的 <code>isinstance</code></td></tr><tr><td><strong>实现进度</strong></td><td>Rust 版与 Python 版当前均为 🟠【规划中，未完成】、尚未实现（Rust 在独立分支，Python 端口待排期）</td></tr></tbody></table><p><strong>状态说明</strong>：brainary-agent-sdk 当前<strong>全部接口均为 🟠【规划中，未完成】</strong>——架构已规划、尚未实现；下方给出的类型、签名、字段均为<strong>已承诺的形态</strong>，供对齐讨论，非占位草案。（⚪ = 暂缓 / 不纳入，非交付接口。）</p><h2 id="接口层面明确不做-与-rust-一致" tabindex="-1">接口层面明确不做（与 Rust 一致） <a class="header-anchor" href="#接口层面明确不做-与-rust-一致" aria-label="Permalink to &quot;接口层面明确不做（与 Rust 一致）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>状态</th><th>归属</th><th>说明</th></tr></thead><tbody><tr><td>token 级流式输出</td><td>🟠</td><td>上游</td><td>现为<strong>步级</strong>流：每完成一步产出一条 <code>Message</code></td></tr><tr><td>跨进程 resume（从 transcript 续跑）</td><td>🟠</td><td>上游</td><td>底层无「从历史重建 agent」构造器；进程内 resume 规划支持</td></tr><tr><td>步内中断</td><td>🟠</td><td>上游</td><td>现为<strong>步边界</strong>协作式中断</td></tr><tr><td>真实 cost 计量</td><td>🟠</td><td>上游</td><td><code>total_cost_usd</code> / <code>usage</code> 恒 <code>None</code>，类型已就位，见 <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#cost">消息模型</a></td></tr><tr><td>结构化 <code>tool_use</code> / <code>tool_result</code> 填充</td><td>🟠</td><td>上游</td><td>类型已建齐，v1 不填充</td></tr><tr><td>自动压缩</td><td>🟠</td><td>core</td><td>旋钮就位，落地由 core 拥有</td></tr><tr><td>手动 <code>compact()</code></td><td>⚪</td><td>不暴露</td><td><strong>故意</strong>不给（footgun）</td></tr></tbody></table><h2 id="coverage-matrix" tabindex="-1">覆盖矩阵：接口全表面与决策 <a class="header-anchor" href="#coverage-matrix" aria-label="Permalink to &quot;覆盖矩阵：接口全表面与决策 {#coverage-matrix}&quot;">​</a></h2><p>这张表把 agent SDK 的<strong>全部</strong>候选公开接口过一遍，<strong>站在「编码智能体 agent SDK」这一目标工具的位置</strong>逐行裁决，每行给出 Brainary 的处置决策与一句理由。它是本站<strong>权威</strong>的「扫过完整表面 × 我方决策」总表：凡判 ⚪（暂缓/仅登记）的都给出明确理由（多为 CLI 子进程内部管线、已退役接口或工具宇宙不同者），而非把边缘接口一概推迟——传输、流事件、限流、后台任务消息、<strong>命令沙箱</strong>、插件、Hooks、内置工具目录、设置来源等面均从目标工具视角逐项重判并登记在下。Python 与 Rust <strong>决策一致</strong>（同一接口清单）。</p><p><strong>决策标签</strong>：🟠 纳入本站交付面（【规划中，未完成】——架构已规划、尚未实现） · ⬇️ 下沉核心层（非本站门面职责） · ⚪ 暂缓 / 不纳入（仅登记，附理由）。凡「纳入」的接口当前一律为 🟠，不再细分实现档位。</p><h3 id="入口与函数" tabindex="-1">入口与函数 <a class="header-anchor" href="#入口与函数" aria-label="Permalink to &quot;入口与函数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由 / 去处</th></tr></thead><tbody><tr><td><code>query()</code></td><td>🟠</td><td>一次性入口，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/query-and-client.html">两个入口</a></td></tr><tr><td>有状态多轮客户端</td><td>🟠</td><td>→ <code>BrainaryClient</code>，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/query-and-client.html">两个入口</a></td></tr><tr><td><code>tool()</code></td><td>🟠</td><td><code>@tool</code> 装饰器，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/tools.html">自定义工具</a></td></tr><tr><td><code>create_sdk_mcp_server()</code></td><td>🟠</td><td>命名能力单元（对应 Rust <code>FunctionTools</code>），<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/tools.html#create-sdk-mcp-server">自定义工具</a></td></tr><tr><td><code>list_sessions</code> / <code>get_session_messages</code> / <code>get_session_info</code> / <code>rename_session</code></td><td>🟠</td><td>待跨进程持久化底座，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html">会话管理</a></td></tr><tr><td><code>tag_session</code></td><td>⚪</td><td>可选</td></tr></tbody></table><h3 id="类型" tabindex="-1">类型 <a class="header-anchor" href="#类型" aria-label="Permalink to &quot;类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由 / 去处</th></tr></thead><tbody><tr><td>统一配置对象</td><td>🟠</td><td><code>Options</code>，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/options.html">Options</a></td></tr><tr><td><code>SystemPromptPreset</code></td><td>🟠</td><td>系统提示三来源，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/options.html#系统提示-systemprompt">Options</a></td></tr><tr><td><code>Message</code> / <code>ContentBlock</code></td><td>🟠</td><td>一对一镜像，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html">消息模型</a></td></tr><tr><td><code>billing_cap</code> / <code>total_cost_usd</code> / <code>usage</code></td><td>🟠</td><td>成本面，<code>billing_cap</code> 规划就位、值待上游，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#cost">成本</a></td></tr><tr><td><code>PermissionMode</code> / <code>CanUseTool</code> / <code>PermissionResult</code></td><td>🟠</td><td>控制面三件套，占位，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a>（已从占位改写为完整规范）</td></tr><tr><td><code>ToolPermissionContext</code></td><td>🟠</td><td><code>CanUseTool</code> 回调自身的入参，属控制面 CORE，占位，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a></td></tr><tr><td><code>PermissionUpdate</code> / <code>PermissionRuleValue</code></td><td>🟠</td><td>运行期改规则并持久化的<strong>公开</strong>机制（非 CLI 内部），占位，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a></td></tr><tr><td><code>AgentDefinition</code>（子 agent）</td><td>🟠</td><td>提升为 SDK 表面 <code>Options.agents</code>：程序化子 agent 是这类编码智能体的头等特性；深度装配仍可交叉引用 核心层</td></tr><tr><td><code>ToolAnnotations</code></td><td>🟠</td><td>工具行为提示，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/tools.html#toolannotations-工具行为提示-架构占位">自定义工具</a></td></tr><tr><td><code>McpServerConfig</code> 家族</td><td>🟠</td><td><code>mcp_server()</code> 糖只收 URL；需补 stdio <code>args</code>/<code>env</code> 与<strong>鉴权 <code>headers</code></strong>（缺 headers 无法配置需鉴权的远程 MCP），MCP</td></tr><tr><td>语义错误模型</td><td>🟠</td><td><code>BrainaryError</code> 异常类树（<code>BuildError</code> / <code>RateLimitError</code> / <code>ToolExecutionError</code> …），<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/errors.html">错误处理</a></td></tr><tr><td><code>CLINotFoundError</code> / <code>CLIConnectionError</code> / <code>ProcessError</code> / <code>CLIJSONDecodeError</code></td><td>⚪</td><td>CLI 子进程传输产物（缺二进制/连不上/非零退出/JSON 解析失败）；brainary-agent-sdk 是<strong>进程内库</strong>，无此层（OUT），<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/errors.html#cli-error-family-out">错误处理</a></td></tr><tr><td>Hook types</td><td>🟠</td><td>确定性治理层，整只子系统已成规范，占位，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/hooks.html">Hooks</a></td></tr><tr><td><code>OutputFormat</code> / <code>ThinkingConfig</code> / <code>EffortLevel</code></td><td>🟠</td><td>结构化输出对库调用尤其有用；thinking/effort 是现代 agent 控制面，多归 <code>llm_settings</code>，占位</td></tr><tr><td><code>SettingSource</code> / setting_sources</td><td>🟠</td><td>是否加载 user/project/local 设置（含项目记忆文件）；传空 = hermetic，利于 CI，占位</td></tr><tr><td><code>ToolsPreset</code></td><td>⚪</td><td>编码智能体预设的工具宇宙与 Brainary 不同，不移植（OUT）</td></tr><tr><td><code>SdkBeta</code></td><td>⚪</td><td>已退役，仅登记（OUT）</td></tr><tr><td><code>Transport</code>（自定义传输）</td><td>⚪</td><td>CLI 子进程逃生口；Brainary 内部自持传输，不作公共旋钮</td></tr><tr><td><code>StreamEvent</code>（partial 消息）</td><td>🟠</td><td>归 token 级流式——现为步级，类型面待上游</td></tr><tr><td><code>RateLimitEvent</code> / <code>RateLimitInfo</code></td><td>🟠</td><td>面向托管模型的 agent SDK 应暴露限流状态以便退避，占位</td></tr><tr><td>后台任务消息（<code>TaskStarted</code> / <code>TaskProgress</code> / <code>TaskNotification</code> + <code>TaskUsage</code>）</td><td>🟠</td><td>随 <code>stop_task</code>；v1 无后台任务模型</td></tr><tr><td><code>SandboxSettings</code> 家族</td><td>🟠</td><td>宿主内<strong>命令沙箱</strong>：约束 bash 工具的文件/命令/网络，占位。与 PoA/wasm 隔离整只 <code>.poa</code> 是不同概念，两者都要</td></tr><tr><td><code>SdkPluginConfig</code> / plugins</td><td>🟠</td><td>SDK <strong>程序化</strong>加载本地插件包（commands/agents/mcp）；「CLI 专属」判断有误，占位</td></tr></tbody></table><h3 id="内置工具与授权" tabindex="-1">内置工具与授权 <a class="header-anchor" href="#内置工具与授权" aria-label="Permalink to &quot;内置工具与授权&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由 / 去处</th></tr></thead><tbody><tr><td><strong>内置工具目录</strong>（Read/Write/Edit/Bash/Glob/Grep/WebFetch/WebSearch/Agent 等，Brainary 原生名）</td><td>🟠</td><td>编码智能体 SDK 的定义性面：文件类规划由 <code>FolderPrimitive</code> 装配（schema 待精化），shell/web/交互/任务/子 agent 均规划中，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/builtin-tools.html">内置工具目录</a></td></tr><tr><td><code>allowed_tools</code> / <code>disallowed_tools</code></td><td>🟠</td><td>声明式授权清单（可用性 ≠ 授权），占位，<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a></td></tr><tr><td><code>permission_mode</code>（6 模）/ <code>CanUseTool</code> / <code>PermissionResult</code></td><td>🟠</td><td>控制面三件套，占位，指向已改写为完整规范的 <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a></td></tr></tbody></table><h3 id="运行时控制-客户端方法" tabindex="-1">运行时控制（客户端方法） <a class="header-anchor" href="#运行时控制-客户端方法" aria-label="Permalink to &quot;运行时控制（客户端方法）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由</th></tr></thead><tbody><tr><td><code>connect</code> / <code>query</code> / <code>interrupt</code> / <code>disconnect</code></td><td>🟠</td><td><code>async with</code> + <code>query</code> / <code>receive_response</code> + <code>await client.interrupt()</code></td></tr><tr><td><code>set_model</code> / <code>set_permission_mode</code> / <code>rewind_files</code></td><td>🟠</td><td>运行时切换/文件检查点未做</td></tr><tr><td><code>get_mcp_status</code> / <code>reconnect_mcp_server</code> / <code>toggle_mcp_server</code></td><td>🟠</td><td>MCP 运行时控制未做</td></tr><tr><td><code>stop_task</code></td><td>🟠</td><td>无后台任务模型</td></tr><tr><td><code>get_server_info</code></td><td>🟠</td><td>部分由只读 getter 覆盖</td></tr></tbody></table><blockquote><p><strong>Brainary 独有</strong>：<code>step_once</code> / <code>revert</code>（手动单步回退）、<code>export_transcript</code>（只读快照）、<code>approx_context_tokens</code> / <code>context_window</code>——见 <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/query-and-client.html#brainaryclient-只读检视与单步">两个入口</a>。</p></blockquote><h2 id="相关" tabindex="-1">相关 <a class="header-anchor" href="#相关" aria-label="Permalink to &quot;相关&quot;">​</a></h2><ul><li><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/overview.html">总览</a> · <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#cost">消息模型</a></li><li><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html">会话管理</a> 🟠 · <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a> 🟠</li><li>对照 Rust：<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk/limits.html">边界与路线图</a></li></ul>',22)])])}const p=d(a,[["render",s]]);export{y as __pageData,p as default};
